// 编译后的 SVG 只落 shadowRoot 内的显式尺寸容器
import { $typst } from 'https://cdn.jsdelivr.net/npm/@myriaddreamin/typst.ts@0/+esm';
const svg = await $typst.svg({ mainContent:data.mainContent, inputs:data.inputs ?? {} });
const doc = new DOMParser().parseFromString(svg, 'image/svg+xml');
const el = document.createElement('div'); el.style.cssText = 'height:640px;overflow:auto';
el.appendChild(document.importNode(doc.documentElement, true)); shadowRoot.appendChild(el);
